Write-Host "=== Fix API Neon @neondatabase/serverless ===" -ForegroundColor Cyan
function Write-B64 { param($p,$b)
  $full = Join-Path (Get-Location).Path $p
  $dir = Split-Path $full -Parent
  if ($dir -and -not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
  $bytes = [Convert]::FromBase64String($b)
  $text = [System.Text.Encoding]::UTF8.GetString($bytes)
  [System.IO.File]::WriteAllText($full, $text, (New-Object System.Text.UTF8Encoding $false))
  Write-Host "  -> $p" -ForegroundColor Gray
}

Write-B64 "frontend\api\db.ts" ""
Write-B64 "frontend\api\migrate.ts" ""
Write-B64 "frontend\api\directions.ts" ""
Write-B64 "frontend\api\engagements.ts" ""
Write-B64 "frontend\api\alerts.ts" ""
Write-B64 "frontend\api\budget.ts" ""
Write-B64 "frontend\package.json" ""

Write-Host "npm install @neondatabase/serverless..." -ForegroundColor Yellow
cd frontend
npm install @neondatabase/serverless --save --legacy-peer-deps 2>&1 | Select-Object -Last 2
cd ..

git add -A
$c = git commit -m "fix: use @neondatabase/serverless, fix API routes 500 error" 2>&1
Write-Host "  $c" -ForegroundColor Gray
git push origin main 2>&1 | Select-Object -Last 2 | Write-Host
Write-Host "DONE - Vercel va redeployer" -ForegroundColor Green
Write-Host "Apres redeploy: POST https://budgetnew.vercel.app/api/migrate" -ForegroundColor Cyan